## Implementation

Create: src/server/supabase/__tests__/smoke-test.test.ts

```typescript
import { getSupabaseClient } from '../client';

describe('Supabase Connection Smoke Test', () => {
  it('can connect and query database', async () => {
    const supabase = getSupabaseClient();

    // If this passes, entire stack works
    const { data, error } = await supabase
      .from('namespaces')
      .select('id, name')
      .limit(1);

    expect(error).toBeNull();
    expect(data).toBeDefined();
  });

  it('can insert and read data', async () => {
    const supabase = getSupabaseClient();
    const testId = crypto.randomUUID();

    // Insert
    const { error: insertError } = await supabase
      .from('namespaces')
      .insert({ id: testId, name: 'Test Namespace' });

    expect(insertError).toBeNull();

    // Read
    const { data, error } = await supabase
      .from('namespaces')
      .select('*')
      .eq('id', testId)
      .single();

    expect(error).toBeNull();
    expect(data?.name).toBe('Test Namespace');

    // Cleanup
    await supabase.from('namespaces').delete().eq('id', testId);
  });
});
```

## Success Criteria

- Test passes on first try (connection configured correctly)
- Can insert and query data (permissions working)
- TypeScript types work (generated types imported)
- Takes < 5 minutes to run

